// STAGE 1: Input Parser
// Extracts category, Amazon.com URLs, and validates input

const input = $input.first().json.chatInput || '';

// Define valid categories
const categories = [
  { key: 'area_rug', patterns: ['area rug', 'area rugs'] },
  { key: 'outdoor_rug', patterns: ['outdoor rug', 'outdoor rugs', 'patio rug'] },
  { key: 'hallway_runner', patterns: ['hallway runner', 'runner rug', 'hall runner', 'runners'] },
  { key: 'shag_rug', patterns: ['shag rug', 'shag rugs', 'shaggy rug'] }
];

// Find selected category
let selectedCategory = null;
let categoryKey = null;
const lowerInput = input.toLowerCase();

for (const cat of categories) {
  for (const pattern of cat.patterns) {
    if (lowerInput.includes(pattern)) {
      selectedCategory = cat.patterns[0].split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
      categoryKey = cat.key;
      break;
    }
  }
  if (selectedCategory) break;
}

// Extract Amazon.com URLs ONLY (reject other Amazon domains)
const amazonComRegex = /(https?:\/\/(?:www\.)?amazon\.com\/[^\s,]+)/gi;
const allAmazonUrls = input.match(amazonComRegex) || [];

// Check for invalid Amazon domains (for warning)
const invalidAmazonRegex = /(https?:\/\/(?:www\.)?amazon\.(?!com)[a-z.]+\/[^\s,]+)/gi;
const invalidUrls = input.match(invalidAmazonRegex) || [];

// Classify URLs into products vs collections
const productUrls = [];
const collectionUrls = [];

allAmazonUrls.forEach(url => {
  const cleanUrl = url.trim().replace(/,+$/, '');

  if (/\/dp\/|\/gp\/product\//.test(cleanUrl)) {
    productUrls.push(cleanUrl);
  } else if (/\/s\?|\/s\/|\/b\/|\/b\?|\/zgbs\//.test(cleanUrl)) {
    collectionUrls.push(cleanUrl);
  }
});

// Extract optional trend focus
const trendFocusMatch = input.match(/focus[:\s]+["']?([^"'\n,]+)["']?/i);
const trendFocus = trendFocusMatch ? trendFocusMatch[1].trim() : null;

// Determine if input is valid
const hasCategory = selectedCategory !== null;
const hasUrls = productUrls.length > 0 || collectionUrls.length > 0;
const isValid = hasCategory && hasUrls;

return [{
  json: {
    rawInput: input,
    selectedCategory: selectedCategory,
    categoryKey: categoryKey,
    productUrls: productUrls,
    collectionUrls: collectionUrls,
    invalidUrls: invalidUrls,
    trendFocus: trendFocus,
    hasCategory: hasCategory,
    hasUrls: hasUrls,
    isValid: isValid,
    timestamp: new Date().toISOString()
  }
}];

// Error Response for invalid input
const input = $input.first().json;

let errorParts = [];

if (!input.hasCategory) {
  errorParts.push('**Category not detected.** Please specify one of:\n- Area Rug\n- Outdoor Rug\n- Hallway Runner\n- Shag Rug');
}

if (!input.hasUrls) {
  errorParts.push('**No Amazon.com URLs found.** Please provide at least one Amazon product or collection URL.');
}

if (input.invalidUrls && input.invalidUrls.length > 0) {
  errorParts.push(`**Note:** ${input.invalidUrls.length} non-US Amazon URL(s) were ignored. Please use amazon.com links only.`);
}

let errorMsg = 'I could not process your request:\n\n' + errorParts.join('\n\n');
errorMsg += '\n\n---\n\n**Example input:**\n';
errorMsg += 'Category: Outdoor Rug\n';
errorMsg += 'https://www.amazon.com/s?k=outdoor+rugs\n';
errorMsg += 'https://www.amazon.com/dp/B08XYZ1234';

return [{ json: { error: true, message: errorMsg } }];

// Prepare Collect List (Process Collection URLs) - split into individual items
const collectionUrls = $input.first().json.collectionUrls || [];

if (collectionUrls.length === 0) {
  return [{ json: { url: null, type: 'no_collections' } }];
}

return collectionUrls.map(url => ({ json: { url, type: 'collection' } }));

// Process Direct Product URLs - split into individual items
const productUrls = $input.first().json.productUrls || [];

if (productUrls.length === 0) {
  return [{ json: { url: null, type: 'no_products' } }];
}

return productUrls.map(url => ({ json: { url, type: 'direct_product' } }));

// Parse Amazon Product Data using Cheerio
const cheerio = require('cheerio');
const results = [];

for (const item of $input.all()) {
  try {
    // Handle both full response format and regular format
    let html = item.json.body || item.json.data || '';
    let url = '';

    if (!html) {
      continue;
    }

    const $ = cheerio.load(html);

    // Extract URL from canonical link in HTML
    const canonicalUrl = $('link[rel="canonical"]').attr('href');
    url = canonicalUrl || 'Amazon Product';

    const name = $('#productTitle').text().trim();
    if (!name) continue;

    const price = $('span.a-price span.a-price-whole').first().text().trim();

    const details = [];
    $('#feature-bullets ul.a-unordered-list li span.a-list-item').each((i, el) => {
      const text = $(el).text().trim();
      if (text && text.length > 0) {
        details.push(text);
      }
    });

    const pattern = $('#inline-twister-expanded-dimension-text-pattern_name').text().trim();

    results.push({
      url,
      name,
      price,
      details,
      pattern,
      scraped_at: new Date().toISOString()
    });
  } catch (error) {
    console.error('Error processing item:', error);
  }
}

return [{
  json: {
    products: results,
    total_scraped: results.length,
    successful_scrapes: results.length,
    failed_scrapes: 0,
    batch_scraped_at: new Date().toISOString()
  }
}];

