    scrapedAt: new Date().toISOString()
  }
}];

// Clean and deduplicate product URLs from collection (matching v1 approach)
const links = $input.first().json.product_links || [];

// Remove duplicates from product_links array
const uniqueLinks = [...new Set(links)];

// Add base URL to make complete URLs
const fullUrls = uniqueLinks.map(link => {
  if (link.startsWith('/')) {
    return `https://www.amazon.com${link}`;
  }
  return link;
});

// Limit to 10 products like v1
const limitedUrls = fullUrls.slice(0, 10);

if (limitedUrls.length === 0) {
  return [{ json: { url: null, type: 'no_products_found', source: 'collection' } }];
}

// Split URLs into individual items for processing one by one
return limitedUrls.map(url => ({ json: { url, type: 'product', source: 'collection' } }));

// Get category key for Extern API calls
const categoryKey = $('Input Parser1').first().json.categoryKey;
const selectedCategory = $('Input Parser1').first().json.selectedCategory;

return [{
  json: {
