} catch (e) { pinterest = { items: [] }; }

try {
  blogs = $('Fetch Blogs').first().json || { items: [] };
} catch (e) { blogs = { items: [] }; }

// Extract images for analysis (limit to 2-3 per source)
const extractImages = (items, source, limit = 3) => {
  return (items || [])
    .filter(item => item.image_base64)
    .slice(0, limit)
    .map(item => ({
      source: source,
      id: item.id,
      caption: item.caption || '',
      image_base64: item.image_base64,
      mime_type: item.image_mime_type || 'image/jpeg'
    }));
};

const socialImages = [
