let output = $input.first().json.output;

// Parse AI output (handle markdown code blocks if present)
if (typeof output === 'string') {
  output = output.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  try {
    output = JSON.parse(output);
  } catch (e) {
    return [{ json: { error: 'Failed to parse classifier output', filteredProducts: [] } }];
  }
}

const classifications = output.classifications || [];
const amazonProducts = $('Deduplicate + Combine Final Amazon Product List').first().json.amazonProducts || [];

// Filter to only matching products
const matchingUrls = new Set(
  classifications
    .filter(c => c.match_status === 'match' && c.confidence !== 'low')
    .map(c => c.url)
);

const filteredProducts = amazonProducts
  .filter(p => matchingUrls.has(p.url))
  .map(p => {
    const classification = classifications.find(c => c.url === p.url);
    return {
      ...p,
      classification_reasoning: classification?.reasoning || ''
    };
  });

return [{
  json: {
    filteredProducts: filteredProducts,
    totalFiltered: filteredProducts.length,
    classificationSummary: output.summary || {}
  }
}];

